(1, NULL, NULL, 3, 'La Rosa 1551', '<p>Casa de Adrogué</p>', 'La Rosa, 1551, Adrogué, Buenos Aires, Argentina', 550000.00, 3, 1, 100, 1, '2025-01-01', '2027-12-31', '<p>Seguro de Hogar</p>', NULL, 'quarterly', 'IPC', NULL, 1.00, NULL, '2025-02-16 14:59:23', '2025-08-30 03:22:04', NULL, -34.8032500, -58.3764931, 'casa'),
(2, NULL, NULL, 2, 'Aranguren 1850 4\"O\", Caballito', '<p><strong>Departamento en Caballito</strong></p><p>Unidad Funcional número <strong>Cincuenta</strong>, ubicada en el <strong>cuarto piso</strong>, destinada a <strong>vivienda</strong>, designada internamente con la letra <strong>\"O\"</strong>;<br>la Unidad Complementaria número <strong>XVIII</strong>, ubicada en el <strong>primer subsuelo</strong>, destinada a <strong>baulera</strong>, designada internamente con el número <strong>18</strong>;<br>y la <strong>una ciento treinta y siete ava (137ª)</strong> parte indivisa de la Unidad Funcional número <strong>Uno</strong>, ubicada en <strong>primer subsuelo y planta baja</strong>, destinada a <strong>cochera</strong>, designada internamente con el número <strong>\"24\"</strong>.</p><p>Todas estas unidades integran el edificio sito en esta <strong>Capital Federal</strong>, con frente a la calle <strong>Doctor Juan Felipe Aranguren</strong>, números:</p><p>1842,1844,1846,1848,1850,1856,1864</p><p>Entre las calles <strong>Teniente General Donato Álvarez</strong> y <strong>Calcena</strong>.</p><p>La Unidad Funcional número <strong>50</strong>, con entrada común por los números <strong>1848</strong> y <strong>1850</strong> de la calle Doctor Juan Felipe Aranguren, consta de las siguientes superficies:</p><p><strong>Superficie cubierta</strong>: 68,50 m²</p><p><strong>Superficie semicubierta</strong>: 5,19 m²</p><p><strong>Superficie total</strong>: <strong>73,69 m²</strong></p><p>Le corresponde un <strong>porcentual de 0,635%</strong>.</p><p><strong>NOMENCLATURA CATASTRAL: </strong>Circunscripción 5,Sección 57, Manzana 24, Parcela 4b.-&nbsp;<br>Partidas Inmobiliarias:</p><ul><li>UF 50 <strong>4034500</strong> DV 01 (<strong>Departamento</strong>)</li><li>UC XVIII:<strong>4034645</strong> DV 01 (<strong>Baulera</strong>)</li><li>UF 1: <strong>4034451</strong> DV 00 (<strong>Cochera</strong>)<br>&nbsp;</li></ul>', 'Doctor Juan Felipe Aranguren, 1850, Buenos Aires, Argentina', 530000.00, 2, 2, 74, 1, '2024-02-01', '2027-01-31', '<p>Seguro de Hogar Allianz Nº 24015/800424</p>', '2026-02-17', 'quarterly', 'IPC', NULL, 1.00, '<ul><li><strong>Cochera:</strong> fija designada con el número 24 del 1º subsuelo&nbsp;</li><li><strong>Baulera:</strong> número 18 en el mismo edificio.&nbsp;</li></ul>', '2025-02-16 14:59:23', '2026-01-23 19:51:16', NULL, -34.6203738, -58.4575228, 'departamento'),
