INSERT INTO `property_claims` (`id`, `property_id`, `user_id`, `owner_id`, `tenant_id`, `title`, `description`, `status`, `priority`, `resolution_notes`, `resolved_at`, `created_at`, `updated_at`) VALUES
(1, 5, 1, 1, NULL, 'Test', 'Estalló la crisis en Red Bull: Lawson podría perder su puesto y Tsunoda pidió su butaca para la próxima carrera El neozelandés tuvo el peor comienzo de la historia de un piloto de la escudería austriaca y su futuro en el equipo estará atado a los próximos resultados', 'resolved', 'low', 'En relación con el pésimo resultado conseguido en la clasificación, agregó: \"Necesito conducir más rápido. Siempre intentamos conseguir el mayor espacio posible en el tráfico, y todos estábamos esperando en la fila, y decidí que quería salir. Pero eso no debería ser la diferencia entre que yo también pudiera pasar, la verdad. Por mucho que me moleste... Tengo un montón de cosas que arreglar antes de poder empezar a mirar ese tipo de cosas“.\r\n\r\nPor otro lado, el neozelandés hizo hincapié en las dificultades que tiene a la hora de controlar el RB21, algo que el cuatro veces campeón de la F1 Max Verstappen también comentó. “Es difícil, ¿sabes? Es difícil conducir, es difícil conseguirlo en ese periodo. Y me encantaría decir que, con el tiempo, obviamente, eso llegará. Simplemente, no tengo tiempo para eso. Así que es algo que necesito controlar”, comentó en diálogo con The Race. A su vez, agregó sobre los problemas para calentar los neumáticos: “No, son sólo las características del coche, la forma en que se conduce el coche. Pero, obviamente, si Max puede conducirlo, yo también debería poder dominarlo”.\r\n\r\nOtra de las directrices que hay que tener en cuenta es que en Red Bull no le temen a cambiar la dupla de pilotos a mitad de temporada. Desde que la escudería del energizante recaló en el año 2005, en siete oportunidades realizaron dicho movimiento, una estrategia que no suele ser común en la categoría. Uno de los casos más recordados ocurrió en 2019, cuando Pierre Gasly fue relegado al equipo Toro Rosso y Alex Albon ocupó su lugar. A este, se suma la situación que se vivió en 2016, cuando después de cuatro Grandes Premios, un joven Max Verstappen tomó el lugar de Daniil Kvyat.', '2025-03-22 20:20:11', '2025-03-22 20:18:10', '2025-03-22 20:20:11'),
(2, 2, 1, 1, 3, 'Deuda AGIP – Partida Nº 4034500', '<p>Revisar una deuda registrada en AGIP correspondiente a la Partida Nº 4034500, por un monto de <strong>$612,147.96 </strong>Adjunto comprobate de deuda y copia de la ultima factura <strong>2025.</strong><br><br>&nbsp;</p>', 'in_progress', 'high', NULL, NULL, '2025-03-24 18:19:07', '2025-04-01 12:17:30'),
(3, 1, 1, 1, 2, 'Alta Suministro de Gas', '<p>Número de Cliente 20312922000 Medidor: 1243862 Gasista Matriculado Nombre : Adrian Alegre Matr. : 20.210 Cat. : 1ra</p>', 'resolved', 'high', NULL, '2025-04-30 11:14:11', '2025-03-25 10:47:48', '2025-04-30 11:14:11'),
(4, 1, 1, 1, 2, 'Propuesta sobre Gastos de Refacción y Opciones de Resolución', '<p><strong>Propuesta sobre Gastos de Refacción y Opciones de Resolución Estimados,&nbsp;</strong></p><p>Quiero compartir con ustedes un resumen de los gastos realizados en la propiedad y las posibles alternativas para su resolución.&nbsp;</p><p>1. <strong>Gastos Realizados</strong>&nbsp;</p><p>El total invertido en mejoras esenciales de la casa (mano de obra y mobiliario que queda en la propiedad, como bañera, bacha, inodoro, conexiones, etc.) fue de aproximadamente $15.000.000. Para dar mayor claridad, si dolarizamos este monto a una cotización de $1.200 por dólar, equivaldría a US$ 12.500.&nbsp;</p><p>Cabe aclarar que hemos realizado otros gastos de carácter estético, que asumimos íntegramente por cuenta propia.&nbsp;</p><p>2. <strong>Valor de la Propiedad&nbsp;</strong></p><p>Solicité una cotización formal a distintas inmobiliarias (Remax y Barceló), pero hasta el momento solo me han dado valores referenciales por mensaje y no por escrito, ya que al no ser el dueño de la propiedad, no quieren emitir un documento formal. 3. Alternativas de Resolución En función de esto, planteo tres escenarios posibles:&nbsp;</p><p><strong>Panorama 1:</strong> Comprar la Casa Si llegamos a un acuerdo sobre el valor de la propiedad, el monto invertido en las refacciones sería descontado del precio de compra.&nbsp;</p><p><strong>Panorama 2: </strong>Venta a un Tercero Si deciden vender la propiedad a otra persona, el monto de las refacciones nos sería reembolsado al concretarse la venta.&nbsp;</p><p><strong>Panorama 3</strong>: Nos Retiramos de la Propiedad Si optan por disponer de la casa sin que la compremos, planteo dos opciones de devolución de los gastos:&nbsp;</p><p><strong>Opción 1:</strong> Devolución en cuotas mensuales, acordando un monto que sea viable.&nbsp;</p><p><strong>Opción 2:</strong> Pago total o en cuotas una vez que la casa se venda.&nbsp;</p><p>Por supuesto, estoy abierto a cualquier modificación o ajuste que consideren necesario. Como mencionamos en su momento, seguiremos realizando mejoras y arreglos por cuenta propia en el tiempo que permanezcamos en la casa.&nbsp;</p><p>Quedo atento a sus comentarios. Saludos,</p>', 'resolved', 'low', '<p>Tras la revisión de la propuesta presentada, ambas partes acuerdan avanzar en la definición de un esquema de devolución del monto invertido en refacciones, conforme a los siguientes escenarios:</p><p><strong>Compra de la Propiedad:</strong> En caso de llegar a un acuerdo sobre la compra, el monto de <strong>$15.000.000 </strong>será descontado del precio final de la transacción.&nbsp;</p><p><strong>Valor de la moneda:</strong> El promedio del dólar blue entre noviembre y diciembre de 2024 fue de aproximadamente <strong>$1.172,50. </strong>El monto de <strong>$15.000.000</strong> equivaldría aproximadamente a <strong>US$ 12.500</strong> usando el promedio.</p><p><strong>Venta a un Tercero:</strong> Si se concreta la venta a un tercero, el monto de la inversión será reembolsado al reclamante en los términos que se definan en la reunión.</p><p><strong>Retiro de la Propiedad sin Compra:</strong> En este caso, se establecerá un plan de pago que contemple:</p><p><strong>Opción 1:</strong> Devolución en cuotas mensuales, según un monto acordado.</p><p><strong>Opción 2:</strong> Pago total o en cuotas una vez que la propiedad sea vendida.</p><p><strong>Próximos Pasos:</strong></p><ul><li>Coordinar una reunión para definir los términos específicos del acuerdo, incluyendo plazos y montos de devolución.</li><li>Formalizar por escrito los compromisos adquiridos.</li><li>Definir un cronograma de ejecución del acuerdo.</li></ul>', '2025-03-31 10:27:10', '2025-03-25 11:20:46', '2025-03-31 10:27:10'),
(6, 2, 1, 1, 3, 'Telegrama deuda - Reclamo del Titular incorrecto', '<p><strong>Remitente</strong>:<br>Metrogas SL<br><br><strong>Destinatario</strong>:&nbsp;<br>ESTEBAN EDUARDO CAMEJO y/o Usuario del servicio. Ref 30012014274</p>', 'pending', 'high', NULL, NULL, '2025-04-24 12:52:57', '2025-04-24 12:52:57'),
(7, 1, 1, 1, 2, '(Marcelo) Segundo Pago por el alta de Servicio de Metrogas', '<p>Hola Marcelo,</p><p>Te escribo porque Tomás me contactó en relación al saldo pendiente del servicio de gas. Quiero aprovechar para detallar algunos gastos extra que tuvimos que afrontar debido a errores en la ejecución del trabajo y a la falta de revisión y seguimiento, lo cual generó una demora de más de 4 meses. Según comentaron otros gasistas matriculados, este tipo de trámite no debería haber demorado más de 20 días, por lo que entendemos que hubo fallas importantes en el proceso.</p><p>También me informaron que los papeles se presentaron recién el 20 de abril, lo cual confirma esta demora.</p><p>A raíz de esta situación, tuvimos que asumir los siguientes costos adicionales:</p><p>1er corte de habilitación por la izquierda: $50.000</p><p>2do corte por cepo: $130.000</p><p>Reformas para la 1ra inspección:</p><p>Mano de obra: $100.000</p><p>Materiales: $50.000</p><p>Total de gastos adicionales: $330.000</p><p>Teniendo en cuenta que el monto pendiente que mencionaste es de $280.000, creemos que estos gastos extras deberían ser considerados para compensar ese saldo.</p><p>Quedamos atentos a tu respuesta para poder cerrar este tema de la mejor manera posible.</p><p>Saludos,</p>', 'resolved', 'low', 'No hay respuesta, por lo cual se entiende que no hay reclamos. \r\n\r\nSe cierra la indicencia por no tener respuesta.', '2025-06-03 14:45:03', '2025-05-11 07:30:16', '2025-06-03 14:45:03'),
(8, 2, 1, 1, 3, 'Arreglos de carpintería (Alacena)', '<p>Se deja constancia de que, debido al desgaste producido por el uso diario, fue necesario realizar un arreglo en la alacena del inmueble. Por tal motivo, se reconoce al inquilino un importe de <strong>$175.000</strong>, el cual será aplicado como crédito sobre el alquiler correspondiente al mes de <strong>junio de 2025</strong>.</p>', 'resolved', 'medium', 'Se informa que se ha resuelto una incidencia relacionada con el mobiliario de cocina, específicamente una alacena, la cual presentaba desgaste por el uso cotidiano.\r\nTras la revisión correspondiente, se procedió a realizar las reparaciones necesarias para garantizar su correcto funcionamiento.\r\n\r\nComo reconocimiento al inquilino por la gestión y/o costos asumidos en la reparación, se otorga un crédito por el importe de $175.000, el cual será aplicado al pago del alquiler correspondiente al mes de junio de 2025.', '2025-05-12 16:55:37', '2025-05-12 16:53:18', '2025-05-12 16:55:37'),
(9, 1, 1, 1, 2, 'Reclamo del vecino', '<p>Se detectó un problema de filtración de humedad en una habitación de planta alta de la vivienda ubicada a la izquierda, cuya pared linda con el tejado de la casa vecina. El origen de la filtración parece estar en una refacción anterior realizada en el tejado, durante la cual se colocó una chapa de cinc como lateral. Para su instalación, se habría picado parte de la pared de la medianera que pertenece a la vivienda afectada, lo que habría dejado el muro expuesto y ahora permite el ingreso de humedad.</p><p>El propietario de la vivienda afectada permitió el acceso para revisar la zona y actualmente está gestionando un presupuesto para realizar las reparaciones correspondientes.</p><p>Adicionalmente, se había detectado anteriormente una filtración en la salida de la cocina hacia el patio, atribuida a una mala instalación de membrana, la cual fue corregida y sellada nuevamente.</p><p>El conflicto se centra en que el propietario afectado considera que los daños en su pared fueron causados por la intervención anterior, por lo que espera que la parte responsable se haga cargo, en forma parcial o total, del costo de la reparación.</p>', 'resolved', 'medium', '<p><strong>Problema resuelto</strong></p><p>Luego de haberse identificado una filtración de humedad en la planta alta de la vivienda ubicada a la izquierda, y tras el análisis conjunto con el propietario de dicha unidad, se confirmó que la intervención previa en el tejado —específicamente la instalación de una chapa lateral que afectó la medianera— habría dejado el muro expuesto a las inclemencias climáticas, generando el ingreso de humedad.</p><p>Ambas partes acordaron que, si bien no se pudo determinar con certeza la responsabilidad directa del daño, y dado que la medianera pertenece a nuestra propiedad, se procedería a dividir los costos de reparación en partes iguales.</p><p>El propietario afectado, Germán Alberto Bisero, presentó un presupuesto por un total de <strong>$1.120.000</strong>, el cual contempla trabajos de reparación de tejas, carga, revoques con hidrófugo y aplicación de membrana, entre otros. Conforme al acuerdo, se realizó una <strong>transferencia de $560.000</strong> en fecha <strong>27/06/2025</strong>, a la cuenta informada del Sr. Bisero (CVU 0000003100094809566670 - Mercado Pago), en concepto del 50% correspondiente a nuestra parte del costo total de la obra.</p><p>Adjuntos a esta nota se encuentran el presupuesto y el comprobante de la transferencia realizada.</p><p>Finalmente, la <strong>supervisión de la ejecución y finalización de los trabajos</strong> estará a cargo de Tomás, junto con el Sr. Germán.</p>', '2025-07-03 18:06:28', '2025-06-03 15:04:54', '2025-07-03 18:06:28'),
(10, 2, 1, 1, 3, 'Formalización de reclamo - Filtración techo baño 4° O', '<p>Dirigido a: Administración Reyes<br>De: Adrian Escalada - Propietario<br>Unidad: Aranguren 1850, 4° “O”<br>Email:adrianescalada@gmail.com</p><p><strong>OBJETO DE LA PRESENTE</strong><br>Por medio de la presente, me dirijo a ustedes como propietario de la unidad 4° \"O\" para solicitar su colaboración en la resolución de un problema de filtraciones de agua, humedad y aparición de hongos en el techo del baño principal de mi unidad habitacional.<br><br><strong>Aclaración importante:</strong> Las gestiones previas fueron realizadas por mi inquilino, el <strong>Sr. Julián Cappa</strong>, quien mantuvo comunicación directa con la administración. Sin embargo, ante la falta de resolución del problema, procedo como propietario a formalizar este reclamo.<br><br><strong>ANTECEDENTES Y CRONOLOGÍA</strong><br>Primer Contacto - 15 de julio de 2025</p><p>Mi inquilino, Julián Cappa, reportó el problema de humedad considerable en el techo del baño principal<br>Envió audios explicativos del problema a través de WhatsApp<br>Se le solicitaron fotografías como evidencia</p><p>Seguimiento - 15 de julio de 2025 (20:07 hs)</p><p>El Sr. Cappa remitió cuatro (4) fotografías que documentan claramente:</p><ul><li>Manchas de humedad extensas</li><li>Pintura descascarada y desprendida</li><li>Presencia visible de hongos (manchas oscuras)</li><li>Deterioro progresivo del material del techo</li></ul><p><strong>Respuestas Administrativas</strong></p><p>17 de julio: Sin respuesta a la consulta del inquilino<br>21 de julio: Sin respuesta a la reiteración del inquilino<br>21 de julio (13:55): María José informó que Ornela estaba internada y que consultaría disponibilidad de plomero<br>25 de julio: Sin respuesta al seguimiento del inquilino<br>28 de julio: María José indicó que estaba \"tomando nota para coordinar con el plomero\"</p><p><strong>SITUACIÓN ACTUAL</strong><br>Han transcurrido más de 34 días desde el primer reporte realizado por mi inquilino, y comprendo que pueden haber surgido complicaciones administrativas (como la situación de salud de Ornela, a quien envío mis mejores deseos de recuperación). Sin embargo, como propietario responsable, considero necesario formalizar esta solicitud para poder coordinar:</p><ul><li>Inspección técnica del problema</li><li>Contacto con profesional plomero</li><li>Plan de acción para la reparación</li><li>Cronograma de solución</li><li>&nbsp;</li></ul><p><strong>PROBLEMÁTICA Y RIESGOS</strong></p><ul><li>Daños Materiales</li><li>Deterioro progresivo del techo y pintura</li><li>Posible compromiso de la estructura del cielorraso</li><li>Daño a elementos del baño</li><li>Riesgos para la Salud</li><li>Proliferación de hongos y moho (claramente visible en las fotografías)</li><li>Exposición a esporas que pueden causar:<ul><li>Problemas respiratorios</li><li>Alergias</li><li>Irritación de mucosas</li><li>Complicaciones en personas sensibles</li></ul></li></ul><p><strong>Origen Probable</strong></p><ul><li>Filtración desde la unidad superior (5° \"O\")</li><li>Posible problema en instalaciones sanitarias comunes</li><li>Deficiencias en impermeabilización</li></ul><p><strong>SOLICITUD</strong><br>Respetuosamente solicito su colaboración para:</p><ul><li>Programar una inspección técnica por parte de un plomero</li><li>Identificar el origen de la filtración</li><li>Coordinar la reparación del problema</li><li>Evaluar el tratamiento de la zona afectada por hongos</li><li>Establecer un cronograma de trabajos</li><li>Coordinar previamente el acceso a mi unidad</li><li>Considerar la reparación de los daños en pintura y elementos del baño</li></ul><p><strong>TIEMPO PARA RESPUESTA</strong><br>Agradecería una respuesta en un plazo de <strong>diez (10) días hábiles</strong> para poder coordinar juntos:</p><p>La programación de la inspección técnica<br>El inicio de las gestiones necesarias</p><p>Comprendo que estas gestiones llevan tiempo, pero dado el tiempo transcurrido y los riesgos para la salud asociados a la presencia de hongos, consideraría muy valioso poder contar con un cronograma aproximado de acciones.<br><br><strong>DOCUMENTACIÓN ADJUNTA</strong></p><ul><li>Fotografías del estado actual (4 imágenes del 15/07/2025) tomadas por mi inquilino</li><li>Capturas de pantalla de conversaciones WhatsApp entre el inquilino y la administración</li><li>Registro cronológico de comunicaciones</li></ul><p><strong>DATOS DE CONTACTO PARA RESPUESTA</strong><br>Propietario: Adrian Escalada<br>Email: adrianescalada@gmail.com<br>Unidad: Aranguren 1850, 4° \"O\"</p><p>Inquilino: Julián Cappa (para coordinación de acceso)</p><p>WhatsApp: &nbsp;11 4043-3279</p><p><br>Sin otro particular, y agradeciendo de antemano su atención y colaboración para resolver esta situación que afecta la habitabilidad de mi propiedad, los saludo muy cordialmente.<br><br>Adrian Escalada<br><strong>Propietario - Unidad 4° \"O\"</strong><br>&nbsp;</p><p>NOTA: Se recomienda enviar esta comunicación por email y WhatsApp, conservando constancia de envío.</p>', 'resolved', 'urgent', '<p>Hola Julián,</p><p>Te aviso que la parte de <strong>humedad y pintura del baño ya fue solucionada</strong>.</p><p>Con respecto al <strong>extractor</strong>, lo revisaron y me informaron que el inconveniente se debió a un <strong>recalentamiento por exceso de uso</strong>, lo que provocó que el eje del ventilador se desviara.<br>Por lo tanto, <strong>no se trata de un problema de filtración</strong>, sino de un <strong>desperfecto propio del aparato</strong>.</p><p>Si bien este tipo de daños no corresponderían al propietario (ya que suelen originarse por uso o mantenimiento), <strong>nos haremos cargo del reemplazo</strong> en esta oportunidad.</p><p>¿Podrías por favor <strong>encargarte de la compra y la instalación</strong> del nuevo extractor?<br>El importe correspondiente te lo <strong>descontamos del abono del mes de noviembre de 2025</strong>.</p><p>Gracias por tu colaboración.</p><p>Saludos,<br>Adrián</p>', '2025-10-16 11:25:54', '2025-08-19 02:15:21', '2025-10-16 11:25:54'),
(13, 5, 1, 1, NULL, 'PropertyClaim', '<p>PropertyClaim</p>', 'pending', 'low', NULL, NULL, '2025-08-23 02:41:58', '2025-08-23 02:41:58'),
(27, 3, 1, 1, NULL, 'Revisión del monto del alquiler de octubre', '<p>Hola Roberto Nayib Mateo,</p><p>Hemos revisado el cálculo del alquiler de octubre según los ajustes que nos enviaste y también usando la aplicación GestorAlquiler.</p><p>Según los porcentajes que mencionaste (Abril 2,8 %, Mayo 1,5 %, Junio 1,6 %), el valor actualizado resulta aproximadamente $ 517.721.</p><p>Según GestorAlquiler, el valor para el trimestre agosto–noviembre 2025 es $ 516.368,64.</p><p>La diferencia entre ambos valores es mínima ($1.352,36), probablemente debido a redondeos, fechas de corte distintas o diferencias en la aplicación del IPC.</p><p>Por nuestra parte, el monto abonado corresponde correctamente al ajuste vigente según la metodología estándar de IPC utilizada por la aplicación.<br>No obstante, quedamos a disposición para regularizar la diferencia si así lo consideras conveniente.</p><p>Gracias por tu comprensión,<br>Viviana Escalada &nbsp;Inquilino 2°B – (Lucia Camarda)</p>', 'resolved', 'low', 'Se realizó el pago restante reclamado por el propietario por la suma de 1352,36 pesos.\r\n\r\nSe deja constancia en:\r\nhttps://gestoralquiler.com.ar/properties/3/payments/192', '2025-10-12 00:06:08', '2025-10-09 23:45:52', '2025-10-12 00:06:08'),
(35, 3, 11, 11, NULL, 'Ajuste de alquiler desde 1/11/25', '<p>Hola Viviana, espero se encuentren , junto a la Sra.Lucia, te envío el ajuste de alquiler desde 1/11/25, saludos<br><br>Ajuste alquiler 2°B.-Spiro :&nbsp;</p><p>Agosto $517.721 -&nbsp;<br>Julio 1,9 % -<br>Agosto 1,9% -<br>Setiembre 2,1% -<br><br>Nuevo valor desde 1/11/25: <strong>$548.871.</strong>-</p>', 'resolved', 'low', '<p>Nuevo valor desde 1/11/25: <strong>$548.871.</strong>-</p>', '2025-10-19 19:11:45', '2025-10-19 19:10:13', '2025-10-19 19:11:45'),
(37, 49, 114, 114, NULL, 'Falta de pago', '<p>falta pagar abl</p>', 'resolved', 'high', 'ya fue pagado', '2025-12-04 17:13:10', '2025-12-04 17:03:23', '2025-12-04 17:13:10'),
(38, 3, 1, 13, NULL, 'Ajustes Febrero 2026', '<p>2°B- Camarada,Lucia-$ 548.871 + Octubre 2,3,% -: Noviembre 2,5% -Diciembre 2,8% -Nuevo valor desde 1/2/26:&nbsp;</p><h2><strong>$591.647</strong></h2>', 'in_progress', 'medium', NULL, NULL, '2026-01-23 20:11:10', '2026-01-23 20:19:10'),
(39, 24, 26, 26, NULL, 'ACTA DE LA JUNTA GENERAL ORDINARIA 2026', '<p>En Llucmajor, a 4 de febrero de 2026, siendo las 18:45 horas, se celebra Junta General<br>Ordinaria de la Comunidad de Propietarios Can Alegria, en la entrada del edificio sito en C/<br>Sindicat nº 66, previa convocatoria realizada en fecha 5 de enero de 2026, conforme a lo<br>establecido en la Ley de Propiedad Horizontal.</p>', 'resolved', 'high', '<p>No habiendo más asuntos que tratar, siendo las 20:20 horas, se da por finalizada la Junta, levantándose la presente acta que,<br>leída y aprobada, se firma en prueba de conformidad.</p>', '2026-02-07 02:34:16', '2026-02-06 20:26:38', '2026-02-07 02:34:16'),
(40, 24, 26, 26, NULL, 'Presupuestos Filtracion de agua', '<p><strong>Fachadas, terrazas, bajantes y claraboya</strong><br>Se acuerda solicitar presupuestos a empresas especializadas, los cuales serán evaluados y sometidos a aprobación en una futura Junta de Propietarios que será convocada al efecto.</p>', 'pending', 'high', NULL, NULL, '2026-03-03 12:48:12', '2026-03-03 12:48:12');
