INSERT INTO `reviews` (`id`, `user_id`, `property_id`, `name`, `usage_type`, `content`, `status`, `rating`, `created_at`, `updated_at`) VALUES
(6, 1, 2, 'Mariana C.', 'owner', '“Uso GestorAlquiler hace más de un año para administrar mi departamento. Antes llevaba todo en Excel y siempre me olvidaba de los aumentos o de mandar recordatorios. Con esta herramienta ahora tengo todo en un solo lugar: contratos, pagos y vencimientos. Lo que más valoro es que me avisa automáticamente cuándo actualizar el alquiler según el IPC y que puedo subir los comprobantes de pago de cada inquilino. Además, al ser gratis, no tuve que invertir nada para empezar. Me dio mucha tranquilidad y orden.”\r\n\r\n— Mariana C., Propietaria, Argentina', 'approved', 5, '2025-08-31 02:25:01', '2025-08-31 02:29:07'),
(7, 5, 1, 'Tomás M', 'tenant', 'Excelente Aplicación. Facil de usar, intuitiva, completa y muy agradable a la vista. Recomendable 100%', 'approved', 5, '2025-08-31 17:00:44', '2025-08-31 17:56:31'),
(8, 10, 1, 'Patricia E.', 'owner', 'El uso de Gestión Alquiler me permite organizar de una manera ágil y práctica el manejo del alquiler de mi propiedad.  La ventaja de tener todo en un solo lugar (contrato, comprobantes de pago,arreglos,incrementos, etc) ahorra mucho tiempo y optimiza la gestión de una manera más cómoda y prolija. Excelente herramienta!!!', 'approved', 5, '2025-08-31 18:27:31', '2025-08-31 18:31:00'),
(9, 9, 4, 'Lisandro E.', 'tenant', 'Me sorprendió que fuera gratis y tan completo. Puedo llevar todo el control de mis propiedades sin invertir nada y con la seguridad de que los cálculos de actualización están correctos. Realmente práctico y confiable.', 'approved', 5, '2025-08-31 18:50:12', '2025-08-31 18:50:54'),
(11, 12, 4, 'Valentina', 'tenant', 'Valentina E. – Inquilina en Glew\r\nAhora puedo subir mis comprobantes de pago directamente al sistema y recibir avisos de vencimiento. Es muy cómodo y transparente; siempre sé cuánto debo pagar y cuándo. Me da tranquilidad y evita malentendidos con el propietario.', 'approved', 5, '2025-09-26 18:32:03', '2025-09-26 18:36:53'),
(12, 11, 1, 'Viviana', 'owner', 'Exelente aplicación y gratuita.\r\nTe optimiza los tiempos , es muy certera y efectiva con los montón.\r\n\r\nAyuda a la organización  de tus finanzas.', 'approved', 5, '2025-09-30 14:57:37', '2025-10-03 00:52:02'),
(13, 118, 50, 'Joaquin Peralta', 'owner', '100', 'approved', 5, '2025-12-04 19:11:55', '2025-12-05 12:07:42');
